#include<bits/stdc++.h>
using namespace std;

int main()
{
	int a,b,c,d,e,hw,flag;
	scanf("%d%d",&a,&b);
	if(a%2==0) a=a+1;
	for(int i=a;i<=b;i++)
	{
		d=i;
		hw=i;
		c=0;
		while(d>0)
		{
			e=d%10;
			c=c*10+e;
			d/=10;
		}
		if(c==i)
		{
			flag=0;
			for(int j=2;j<=sqrt(hw);j++)
			{
				if(hw%j!=0)
				{
					flag=1;
				}
				else
				{
					flag=0;
					break;
				}
			}
			if(flag==1)
			{
				printf("%d\n",hw);
			}
		}
	}
	return 0;
}
